import { useState } from "react";

export default function NestedList() {
  const [data, setData] = useState([
    {
      type: "root",
      title: "Главный список",
      fields: [],
      children: [],
      collapsed: false
    }
  ]);

  // ---------- helpers ----------
  function getNode(copy, path) {
    let node = copy;
    for (let index of path) node = node[index];
    return node;
  }

  function updateTitle(path, value) {
    setData(prev => {
      const copy = structuredClone(prev);
      const node = getNode(copy, path);

      if (node.type === "root") node.title = value;
      else node.titleInput = value;

      return copy;
    });
  }

  function updateField(path, i, value) {
    setData(prev => {
      const copy = structuredClone(prev);
      getNode(copy, path).fields[i].value = value;
      return copy;
    });
  }

  function removeField(path, i) {
    setData(prev => {
      const copy = structuredClone(prev);
      getNode(copy, path).fields.splice(i, 1);
      return copy;
    });
  }

  function addField(path) {
    setData(prev => {
      const copy = structuredClone(prev);
      let node = getNode(copy, path);
      node.fields.push({ id: Date.now(), value: "" });
      return copy;
    });
  }

  function addChildList(path) {
    setData(prev => {
      const copy = structuredClone(prev);
      let node = getNode(copy, path);

      node.children.push({
        type: "child",
        titleInput: "",
        fields: [],
        children: [],
        collapsed: false
      });

      return copy;
    });
  }

  function toggleCollapse(path) {
    setData(prev => {
      const copy = structuredClone(prev);
      let node = getNode(copy, path);
      node.collapsed = !node.collapsed;
      return copy;
    });
  }

  // ---------- recursive render ----------
  function RenderList({ node, path }) {
    const isRoot = node.type === "root";

    return (
      <div
        style={{
          border: "1px solid #ccc",
          borderRadius: 6,
          padding: 10,
          marginTop: 12,
          background: isRoot ? "#f3f3f3" : "#fafafa"
        }}
      >
        {/* Header line */}
        <div style={{ display: "flex", alignItems: "center", marginBottom: 6 }}>
          {/* Collapse button */}
          <button
            onClick={() => toggleCollapse(path)}
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              marginRight: 8,
              transform: node.collapsed ? "rotate(-90deg)" : "rotate(0deg)",
              transition: "0.2s"
            }}
          >
            <svg width="24" height="24">
              <use href="#icon-expand" />
            </svg>
          </button>

          {/* Title */}
          {isRoot ? (
            <h2
              contentEditable
              suppressContentEditableWarning
              onBlur={(e) => updateTitle(path, e.target.innerText)}
              style={{ margin: 0, flex: 1 }}
            >
              {node.title}
            </h2>
          ) : (
            <input
              placeholder="Название списка"
              value={node.titleInput}
              onChange={(e) => updateTitle(path, e.target.value)}
              style={{ padding: 6, flex: 1 }}
            />
          )}

          {/* Plus button */}
          <button
            onClick={() =>
              isRoot ? addChildList(path) : addField(path)
            }
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              marginLeft: 8
            }}
          >
            <svg width="28" height="28">
              <use href="#icon-plus" />
            </svg>
          </button>
        </div>

        {/* If collapsed — stop rendering */}
        {node.collapsed ? null : (
          <>
            {/* Fields for CHILD lists */}
            {node.fields.map((f, i) => (
              <div key={f.id} style={{ display: "flex", marginBottom: 6 }}>
                <input
                  value={f.value}
                  onChange={(e) => updateField(path, i, e.target.value)}
                  placeholder="Поле"
                  style={{ padding: 6, flex: 1, marginRight: 10 }}
                />

                <span
                  onClick={() => removeField(path, i)}
                  style={{
                    cursor: "pointer",
                    color: "red",
                    alignSelf: "center",
                    userSelect: "none"
                  }}
                >
                  Удалить
                </span>
              </div>
            ))}

            {/* Child lists */}
            {node.children.map((child, i) => (
              <RenderList
                key={i}
                node={child}
                path={[...path, "children", i]}
              />
            ))}
          </>
        )}
      </div>
    );
  }

  return (
    <div>
      {data.map((item, i) => (
        <RenderList key={i} node={item} path={[i]} />
      ))}
    </div>
  );
}
